// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>

int josephus(int n, int k) {
    if (n == 1) return 1;
    if (k > 0) return (josephus(n - 1, k) + k - 1) % n + 1;
    else return (josephus(n - 1, -k) - (-k) - 1 + n) % n + 1;
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n, k;
        scanf("%d %d", &n, &k);
        printf("%d\n", josephus(n, k));
    }
    return 0;
}

